\]

For the $1$st expression, we have:
\begin{align*}
\overrightarrow{DA}+\overrightarrow{AC}+\overrightarrow{CB}
&= (\overrightarrow{DA}+\overrightarrow{AC})+\overrightarrow{CB} \\[3pt]
&= \overrightarrow{DC}+\overrightarrow{CB} \\[3pt]
&= \overrightarrow{DB} \quad {\color{green}\checkmark}
\end{align*}
For the $2$nd expression, we have:
\begin{align*}
\overrightarrow{DA}+\overrightarrow{AB}
&= \overrightarrow{DB} \quad {\color{green}\checkmark}
\end{align*}
For the $3$rd expression, we have:
\begin{align*}
\overrightarrow{BA}-\overrightarrow{CA}+\overrightarrow{CD}
&= (\overrightarrow{BA}-\overrightarrow{CA})+\overrightarrow{CD} \\[3pt]
&= (\overrightarrow{BA}+\overrightarrow{AC})+\overrightarrow{CD} \\[3pt]
&= \overrightarrow{BC}+\overrightarrow{CD} \\[3pt]
&= \overrightarrow{BD} \\[3pt]
&\neq \overrightarrow{DB} \quad {\color{red}\times}
\end{align*}
Therefore, the correct answer is "I and II only".

Equality I is false. Indeed,
\begin{align*}
\overrightarrow{ED}-\overrightarrow{CD} &= \overrightarrow{ED}+\overrightarrow{DC}\\[3pt]
&= \overrightarrow{EC}\\[3pt]
&\ne \overrightarrow{CE}.
\end{align*}
Equality II is true. Indeed,
\begin{align*}
\overrightarrow{AE}-\overrightarrow{DE}+\overrightarrow{DC}&=(\overrightarrow{AE}+\overrightarrow{ED})+\overrightarrow{DC} \\[3pt]
&= \overrightarrow{AD}+\overrightarrow{DC} \\[3pt]
&= \overrightarrow{AC}.
\end{align*}
Equality III is true. Indeed,
\begin{align*}
\overrightarrow{CB}-\overrightarrow{AB}-\overrightarrow{EA} &=
(\overrightarrow{CB}+\overrightarrow{BA})-\overrightarrow{EA}\\[3pt]
&=\overrightarrow{CA}+\overrightarrow{AE}\\[3pt]
& =\overrightarrow{CE}.
\end{align*}
Therefore, the correct answer is "II and III only".

